UPDATE words SET example_en_2 = 'We agree that quality is most important.', example_ko_2 = '품질이 가장 중요하다는 것에 동의해요.', example_en_3 = 'Can we agree to meet again on Monday?', example_ko_3 = '월요일에 다시 만나기로 합의할 수 있나요?', example_en_4 = 'Both sides agree on the delivery date.', example_ko_4 = '양측이 납품 날짜에 동의해요.', example_en_5 = 'I agree — let us put this in writing.', example_ko_5 = '동의해요 — 이것을 서면으로 작성해요.' WHERE id = 'w_negotiation_A1_05';
UPDATE words SET example_en_2 = 'I want to ask about the delivery schedule.', example_ko_2 = '납품 일정에 대해 묻고 싶어요.', example_en_3 = 'May I ask how long the warranty is?', example_ko_3 = '보증 기간이 얼마인지 여쭤봐도 될까요?', example_en_4 = 'Please ask if you have any questions.', example_ko_4 = '질문이 있으시면 물어보세요.', example_en_5 = 'She asked for a lower minimum order.', example_ko_5 = '그녀는 더 낮은 최소 주문량을 요청했어요.' WHERE id = 'w_negotiation_A1_06';
UPDATE words SET example_en_2 = 'We can offer free delivery on large orders.', example_ko_2 = '대량 주문에 무료 배송을 제공할 수 있어요.', example_en_3 = 'Let me offer you an alternative solution.', example_ko_3 = '대안적인 해결책을 제안해 드릴게요.', example_en_4 = 'They offered a 5% discount right away.', example_ko_4 = '그들은 즉시 5% 할인을 제안했어요.', example_en_5 = 'What can you offer us in return?', example_ko_5 = '우리에게 무엇을 제공할 수 있나요?' WHERE id = 'w_negotiation_A1_07';
UPDATE words SET example_en_2 = 'We signed the deal this morning.', example_ko_2 = '오늘 아침에 거래에 서명했어요.', example_en_3 = 'Is this a good deal for both sides?', example_ko_3 = '이것이 양측 모두에게 좋은 거래인가요?', example_en_4 = 'The deal includes delivery and installation.', example_ko_4 = '거래에는 배송과 설치가 포함돼요.', example_en_5 = 'Let us close the deal by end of day.', example_ko_5 = '오늘 중으로 거래를 마무리합시다.' WHERE id = 'w_negotiation_A1_08';
UPDATE words SET example_en_2 = 'Say yes only when you are fully ready.', example_ko_2 = '완전히 준비됐을 때만 예스라고 하세요.', example_en_3 = 'The client said yes to the revised price.', example_ko_3 = '고객이 수정된 가격에 예스라고 했어요.', example_en_4 = 'Getting a yes early builds good momentum.', example_ko_4 = '초반에 예스를 받으면 좋은 기세가 만들어져요.', example_en_5 = 'She finally said yes after the third offer.', example_ko_5 = '그녀는 세 번째 제안 후에 마침내 예스라고 했어요.' WHERE id = 'w_negotiation_A1_09';
UPDATE words SET example_en_2 = 'It is fine to say no to a bad offer.', example_ko_2 = '나쁜 제안에 아니오라고 해도 괜찮아요.', example_en_3 = 'She said no and walked away calmly.', example_ko_3 = '그녀는 아니오라고 하고 침착하게 자리를 떴어요.', example_en_4 = 'A clear no saves time in negotiations.', example_ko_4 = '명확한 거절이 협상에서 시간을 절약해요.', example_en_5 = 'He said no to the first offer politely.', example_ko_5 = '그는 첫 번째 제안을 정중하게 거절했어요.' WHERE id = 'w_negotiation_A1_10';
UPDATE words SET example_en_2 = 'Can you help us understand the costs better?', example_ko_2 = '비용을 더 잘 이해할 수 있도록 도와주실 수 있나요?', example_en_3 = 'Our legal team will help review the contract.', example_ko_3 = '법무팀이 계약서 검토를 도와줄 거예요.', example_en_4 = 'He helped both sides reach an agreement.', example_ko_4 = '그는 양측이 합의에 도달할 수 있도록 도왔어요.', example_en_5 = 'Good preparation helps in every negotiation.', example_ko_5 = '철저한 준비가 모든 협상에서 도움이 돼요.' WHERE id = 'w_negotiation_A1_11';
UPDATE words SET example_en_2 = 'Can we get more samples before ordering?', example_ko_2 = '주문 전에 샘플을 더 받을 수 있나요?', example_en_3 = 'I need more information before I can decide.', example_ko_3 = '결정하기 전에 정보가 더 필요해요.', example_en_4 = 'Could you offer a little more flexibility?', example_ko_4 = '조금 더 유연성을 제공해 주실 수 있나요?', example_en_5 = 'We want more time to review the proposal.', example_ko_5 = '제안서를 검토할 시간이 더 필요해요.' WHERE id = 'w_negotiation_A1_12';
UPDATE words SET example_en_2 = 'Can we pay less if we order more?', example_ko_2 = '더 많이 주문하면 덜 낼 수 있나요?', example_en_3 = 'I expected less paperwork than this.', example_ko_3 = '이것보다 서류 작업이 덜 할 거라고 예상했어요.', example_en_4 = 'She asked for less time pressure.', example_ko_4 = '그녀는 시간 압박을 덜 받기를 요청했어요.', example_en_5 = 'Less risk means we can accept a lower return.', example_ko_5 = '위험이 낮을수록 더 낮은 수익을 받아들일 수 있어요.' WHERE id = 'w_negotiation_A1_13';
UPDATE words SET example_en_2 = 'We prefer to pay in installments.', example_ko_2 = '할부로 지불하는 것을 선호해요.', example_en_3 = 'How much do we need to pay in advance?', example_ko_3 = '미리 얼마를 지불해야 하나요?', example_en_4 = 'They agreed to pay within thirty days.', example_ko_4 = '그들은 30일 이내에 지불하기로 합의했어요.', example_en_5 = 'We always pay on time — this is our record.', example_ko_5 = '우리는 항상 제때 지불해요 — 이것이 우리의 실적이에요.' WHERE id = 'w_negotiation_A1_14';
