UPDATE words SET example_en_2 = 'Let us talk about the payment terms next.', example_ko_2 = '다음으로 지불 조건에 대해 이야기합시다.', example_en_3 = 'Can we talk by phone instead of meeting?', example_ko_3 = '미팅 대신 전화로 이야기할 수 있나요?', example_en_4 = 'She was easy to talk to during negotiations.', example_ko_4 = '그녀는 협상 중에 이야기하기 쉬웠어요.', example_en_5 = 'We need to talk before making a final decision.', example_ko_5 = '최종 결정을 내리기 전에 이야기해야 해요.' WHERE id = 'w_negotiation_A1_16';
UPDATE words SET example_en_2 = 'Can we meet next week to discuss the terms?', example_ko_2 = '조건을 논의하기 위해 다음 주에 만날 수 있나요?', example_en_3 = 'Let us meet in the middle on price.', example_ko_3 = '가격에서 중간 지점에서 만나요.', example_en_4 = 'They met online and agreed on the main points.', example_ko_4 = '그들은 온라인으로 만나 주요 사항에 합의했어요.', example_en_5 = 'We will meet again after the holidays.', example_ko_5 = '휴일 이후에 다시 만날게요.' WHERE id = 'w_negotiation_A1_17';
