UPDATE words SET example_en_2 = 'Please wait while I consult my team.', example_ko_2 = '팀과 상의하는 동안 기다려 주세요.', example_en_3 = 'We waited a week before responding.', example_ko_3 = '우리는 응답하기 전에 일주일을 기다렸어요.', example_en_4 = 'Do not wait too long to make a decision.', example_ko_4 = '결정을 내리는 데 너무 오래 기다리지 마세요.', example_en_5 = 'They asked us to wait for their final answer.', example_ko_5 = '그들은 최종 답변을 기다려 달라고 했어요.' WHERE id = 'w_negotiation_A1_19';
UPDATE words SET example_en_2 = 'Let us try a different approach this time.', example_ko_2 = '이번에는 다른 접근법을 시도해 봐요.', example_en_3 = 'We will try to reduce the price for you.', example_ko_3 = '귀사를 위해 가격을 낮춰보겠습니다.', example_en_4 = 'Try to see the issue from both sides.', example_ko_4 = '양쪽에서 문제를 보려고 노력하세요.', example_en_5 = 'She tried to close the deal before lunch.', example_ko_5 = '그녀는 점심 전에 거래를 마무리하려고 했어요.' WHERE id = 'w_negotiation_A1_20';
