UPDATE words SET example_en_2 = 'We can sell at this price for large orders.', example_ko_2 = '대량 주문에는 이 가격으로 드릴 수 있어요.', example_en_3 = 'They sell the same product cheaper online.', example_ko_3 = '그들은 온라인에서 같은 제품을 더 싸게 팔아요.', example_en_4 = 'We can sell two hundred units this week.', example_ko_4 = '이번 주에 200개를 팔 수 있어요.', example_en_5 = 'How many units can you sell per month?', example_ko_5 = '한 달에 몇 개를 판매할 수 있나요?' WHERE id = 'w_negotiation_A1_22';
