UPDATE words SET example_en_2 = 'We are here to negotiate a better rate.', example_ko_2 = '더 나은 요율을 협상하기 위해 왔어요.', example_en_3 = 'They negotiated all night to reach a deal.', example_ko_3 = '그들은 거래에 도달하기 위해 밤새 협상했어요.', example_en_4 = 'Good listeners negotiate more effectively.', example_ko_4 = '잘 듣는 사람이 더 효과적으로 협상해요.', example_en_5 = 'We prefer to negotiate face to face.', example_ko_5 = '대면으로 협상하는 것을 선호해요.' WHERE id = 'w_negotiation_B1_01';
UPDATE words SET example_en_2 = 'We had to compromise on the payment terms.', example_ko_2 = '지불 조건에 대해 타협해야 했어요.', example_en_3 = 'Neither side wanted to compromise at first.', example_ko_3 = '처음에는 어느 쪽도 타협하려 하지 않았어요.', example_en_4 = 'Compromise led to a deal that satisfied both.', example_ko_4 = '타협이 양측 모두를 만족시키는 거래로 이어졌어요.', example_en_5 = 'Be ready to compromise on smaller issues.', example_ko_5 = '사소한 문제에서는 타협할 준비를 하세요.' WHERE id = 'w_negotiation_B1_02';
UPDATE words SET example_en_2 = 'They made a concession on the delivery date.', example_ko_2 = '그들은 납품 날짜에 양보를 했어요.', example_en_3 = 'Every concession should have a condition.', example_ko_3 = '모든 양보에는 조건이 있어야 해요.', example_en_4 = 'She made a small concession to close the deal.', example_ko_4 = '그녀는 거래를 마무리하기 위해 작은 양보를 했어요.', example_en_5 = 'Do not give a concession without getting one back.', example_ko_5 = '무언가를 돌려받지 않고 양보를 하지 마세요.' WHERE id = 'w_negotiation_B1_03';
UPDATE words SET example_en_2 = 'Our volume gives us strong leverage here.', example_ko_2 = '우리의 물량이 여기서 강한 협상력을 줘요.', example_en_3 = 'Use your leverage carefully — do not overplay it.', example_ko_3 = '협상력을 신중하게 사용하세요 — 과도하게 사용하지 마세요.', example_en_4 = 'They had more leverage because of the deadline.', example_ko_4 = '마감일 때문에 그들이 더 강한 협상력을 가졌어요.', example_en_5 = 'Identify your leverage before entering talks.', example_ko_5 = '협상에 들어가기 전에 협상력을 파악하세요.' WHERE id = 'w_negotiation_B1_04';
UPDATE words SET example_en_2 = 'Our counterproposal lowers the price by 8%.', example_ko_2 = '우리의 역제안은 가격을 8% 낮춰요.', example_en_3 = 'A counterproposal keeps the negotiation alive.', example_ko_3 = '역제안이 협상을 살아있게 유지해요.', example_en_4 = 'They sent a counterproposal the same afternoon.', example_ko_4 = '그들은 같은 오후에 역제안을 보냈어요.', example_en_5 = 'Always respond to an offer with a counterproposal.', example_ko_5 = '항상 제안에 역제안으로 응답하세요.' WHERE id = 'w_negotiation_B1_05';
UPDATE words SET example_en_2 = 'The deadline is Monday — we must decide now.', example_ko_2 = '마감일이 월요일이에요 — 지금 결정해야 해요.', example_en_3 = 'Can we extend the deadline by one week?', example_ko_3 = '마감일을 일주일 연장할 수 있나요?', example_en_4 = 'A hard deadline speeds up the negotiation.', example_ko_4 = '확정 마감일이 협상 속도를 높여요.', example_en_5 = 'She used the deadline as a negotiating tool.', example_ko_5 = '그녀는 마감일을 협상 도구로 사용했어요.' WHERE id = 'w_negotiation_B1_06';
UPDATE words SET example_en_2 = 'Key stakeholders need to be present today.', example_ko_2 = '주요 이해관계자가 오늘 참석해야 해요.', example_en_3 = 'We must consider all stakeholders in this deal.', example_ko_3 = '이 거래에서 모든 이해관계자를 고려해야 해요.', example_en_4 = 'The stakeholders approved the final terms.', example_ko_4 = '이해관계자들이 최종 조건을 승인했어요.', example_en_5 = 'Identify your stakeholders before you negotiate.', example_ko_5 = '협상하기 전에 이해관계자를 파악하세요.' WHERE id = 'w_negotiation_B1_07';
UPDATE words SET example_en_2 = 'Please follow the agenda so we stay on track.', example_ko_2 = '순조롭게 진행하기 위해 안건을 따라주세요.', example_en_3 = 'The agenda covers price, delivery, and terms.', example_ko_3 = '안건은 가격, 납품, 조건을 다루어요.', example_en_4 = 'She sent the agenda twenty-four hours in advance.', example_ko_4 = '그녀는 24시간 전에 안건을 보냈어요.', example_en_5 = 'Setting the agenda gives you more control.', example_ko_5 = '안건을 설정하면 더 많은 통제권을 가져요.' WHERE id = 'w_negotiation_B1_08';
UPDATE words SET example_en_2 = 'We want to revise the termination clause.', example_ko_2 = '해지 조항을 수정하고 싶어요.', example_en_3 = 'The confidentiality clause must be added.', example_ko_3 = '기밀 유지 조항을 추가해야 해요.', example_en_4 = 'Each clause was reviewed by our legal team.', example_ko_4 = '각 조항은 법무팀에서 검토했어요.', example_en_5 = 'The payment clause specifies thirty days net.', example_ko_5 = '지불 조항은 순 30일을 명시해요.' WHERE id = 'w_negotiation_B1_09';
UPDATE words SET example_en_2 = 'This contract is binding once you sign.', example_ko_2 = '서명하면 이 계약은 구속력이 생겨요.', example_en_3 = 'The agreement became binding at midnight.', example_ko_3 = '합의는 자정에 구속력이 발생했어요.', example_en_4 = 'Verbal agreements are rarely legally binding.', example_ko_4 = '구두 합의는 법적 구속력이 거의 없어요.', example_en_5 = 'Read carefully before signing a binding document.', example_ko_5 = '구속력 있는 문서에 서명하기 전에 주의 깊게 읽으세요.' WHERE id = 'w_negotiation_B1_10';
UPDATE words SET example_en_2 = 'Mutual respect is essential in any negotiation.', example_ko_2 = '상호 존중이 모든 협상에서 필수적이에요.', example_en_3 = 'We look for mutual benefit in every deal.', example_ko_3 = '모든 거래에서 상호 이익을 추구해요.', example_en_4 = 'A mutual agreement was reached after two days.', example_ko_4 = '이틀 후에 상호 합의에 도달했어요.', example_en_5 = 'Mutual trust makes negotiations much smoother.', example_ko_5 = '상호 신뢰가 협상을 훨씬 원활하게 만들어요.' WHERE id = 'w_negotiation_B1_11';
UPDATE words SET example_en_2 = 'Please be transparent about all hidden fees.', example_ko_2 = '모든 숨겨진 수수료에 대해 투명하게 밝혀주세요.', example_en_3 = 'Transparent communication prevents surprises.', example_ko_3 = '투명한 의사소통이 뜻밖의 상황을 방지해요.', example_en_4 = 'She was transparent about her company''s limits.', example_ko_4 = '그녀는 회사의 한계에 대해 투명하게 밝혔어요.', example_en_5 = 'Being transparent builds long-term credibility.', example_ko_5 = '투명함이 장기적 신뢰성을 구축해요.' WHERE id = 'w_negotiation_B1_12';
UPDATE words SET example_en_2 = 'Our position on price is very clear.', example_ko_2 = '가격에 대한 우리의 입장이 매우 명확해요.', example_en_3 = 'She stated her position firmly at the start.', example_ko_3 = '그녀는 시작 시 자신의 입장을 확고하게 밝혔어요.', example_en_4 = 'Understand the other side''s position first.', example_ko_4 = '먼저 상대방의 입장을 이해하세요.', example_en_5 = 'Their position softened after the second meeting.', example_ko_5 = '두 번째 회의 후에 그들의 입장이 유연해졌어요.' WHERE id = 'w_negotiation_B1_13';
UPDATE words SET example_en_2 = 'Is there an alternative to the current terms?', example_ko_2 = '현재 조건에 대한 대안이 있나요?', example_en_3 = 'She offered an alternative payment plan.', example_ko_3 = '그녀는 대안적인 지불 계획을 제안했어요.', example_en_4 = 'Always have an alternative ready going in.', example_ko_4 = '협상에 들어가기 전에 항상 대안을 준비하세요.', example_en_5 = 'The alternative option was cheaper and faster.', example_ko_5 = '대안 옵션이 더 저렴하고 빨랐어요.' WHERE id = 'w_negotiation_B1_14';
UPDATE words SET example_en_2 = 'The penalty for late payment is 1.5% per month.', example_ko_2 = '연체 지불에 대한 위약금은 월 1.5%예요.', example_en_3 = 'We want to reduce the penalty amount.', example_ko_3 = '위약금 금액을 줄이고 싶어요.', example_en_4 = 'The penalty clause applies after seven days.', example_ko_4 = '위약금 조항은 7일 후에 적용돼요.', example_en_5 = 'She negotiated the penalty down to 0.5%.', example_ko_5 = '그녀는 위약금을 0.5%로 낮췄어요.' WHERE id = 'w_negotiation_B1_15';
UPDATE words SET example_en_2 = 'Our main objective is to protect our margin.', example_ko_2 = '우리의 주요 목표는 마진을 보호하는 것이에요.', example_en_3 = 'Define your objectives before the first meeting.', example_ko_3 = '첫 번째 회의 전에 목표를 정의하세요.', example_en_4 = 'The key objective was achieved by the end.', example_ko_4 = '마지막에 핵심 목표가 달성됐어요.', example_en_5 = 'Never lose sight of your main objective.', example_ko_5 = '주요 목표를 절대 잊지 마세요.' WHERE id = 'w_negotiation_B1_16';
UPDATE words SET example_en_2 = 'Quality is the number one priority here.', example_ko_2 = '품질이 여기서 최우선순위예요.', example_en_3 = 'List your priorities before you negotiate.', example_ko_3 = '협상하기 전에 우선순위를 나열하세요.', example_en_4 = 'The delivery date was given the highest priority.', example_ko_4 = '납품 날짜에 가장 높은 우선순위가 부여됐어요.', example_en_5 = 'Know your priorities — and the other side''s too.', example_ko_5 = '자신의 우선순위와 상대방의 우선순위도 파악하세요.' WHERE id = 'w_negotiation_B1_17';
UPDATE words SET example_en_2 = 'We submitted a revision to the payment clause.', example_ko_2 = '지불 조항에 대한 수정안을 제출했어요.', example_en_3 = 'The revision removed the ambiguous language.', example_ko_3 = '수정안이 애매한 표현을 제거했어요.', example_en_4 = 'They accepted our revision with minor changes.', example_ko_4 = '그들은 약간의 변경과 함께 우리의 수정안을 받아들였어요.', example_en_5 = 'A revision should always be sent in writing.', example_ko_5 = '수정안은 항상 서면으로 전달되어야 해요.' WHERE id = 'w_negotiation_B1_18';
UPDATE words SET example_en_2 = 'We need to finalize the terms by next week.', example_ko_2 = '다음 주까지 조건을 마무리해야 해요.', example_en_3 = 'Can we finalize the pricing today?', example_ko_3 = '오늘 가격을 마무리할 수 있나요?', example_en_4 = 'They finalized the agreement at the last minute.', example_ko_4 = '그들은 마지막 순간에 합의를 마무리했어요.', example_en_5 = 'Both sides were happy once they finalized the deal.', example_ko_5 = '거래를 마무리하자 양측 모두 기뻐했어요.' WHERE id = 'w_negotiation_B1_19';
UPDATE words SET example_en_2 = 'We want to resolve this dispute peacefully.', example_ko_2 = '이 분쟁을 평화롭게 해결하고 싶어요.', example_en_3 = 'The dispute arose from unclear contract language.', example_ko_3 = '분쟁은 불명확한 계약 언어에서 발생했어요.', example_en_4 = 'A mediator was brought in to settle the dispute.', example_ko_4 = '분쟁을 해결하기 위해 조정인이 참여했어요.', example_en_5 = 'Clear contracts prevent most business disputes.', example_ko_5 = '명확한 계약이 대부분의 비즈니스 분쟁을 예방해요.' WHERE id = 'w_negotiation_B1_20';
UPDATE words SET example_en_2 = 'Our proposal covers price, scope, and timeline.', example_ko_2 = '우리의 제안서는 가격, 범위, 타임라인을 다루어요.', example_en_3 = 'Please send the proposal by end of week.', example_ko_3 = '이번 주 말까지 제안서를 보내주세요.', example_en_4 = 'She presented the proposal with great clarity.', example_ko_4 = '그녀는 제안서를 매우 명확하게 제출했어요.', example_en_5 = 'The proposal was accepted with minor revisions.', example_ko_5 = '제안서가 약간의 수정과 함께 수락됐어요.' WHERE id = 'w_negotiation_B1_21';
UPDATE words SET example_en_2 = 'The project timeline is tied to our budget.', example_ko_2 = '프로젝트 타임라인이 우리 예산과 연결되어 있어요.', example_en_3 = 'Both sides agreed on a realistic timeline.', example_ko_3 = '양측이 현실적인 타임라인에 합의했어요.', example_en_4 = 'A shared timeline avoids confusion later.', example_ko_4 = '공유 타임라인이 나중의 혼란을 방지해요.', example_en_5 = 'The timeline slipped due to a supply chain issue.', example_ko_5 = '공급망 문제로 타임라인이 지연됐어요.' WHERE id = 'w_negotiation_B1_22';
UPDATE words SET example_en_2 = 'The scope of work must be clearly defined.', example_ko_2 = '작업 범위가 명확하게 정의되어야 해요.', example_en_3 = 'Any change to scope should be documented.', example_ko_3 = '범위에 대한 변경은 문서화되어야 해요.', example_en_4 = 'She reduced the scope to lower the price.', example_ko_4 = '그녀는 가격을 낮추기 위해 범위를 줄였어요.', example_en_5 = 'Scope creep is a major risk in long contracts.', example_ko_5 = '범위 확장은 장기 계약에서 큰 위험이에요.' WHERE id = 'w_negotiation_B1_23';
UPDATE words SET example_en_2 = 'The board will approve the contract on Friday.', example_ko_2 = '이사회가 금요일에 계약을 승인할 거예요.', example_en_3 = 'Our manager needs to approve any changes.', example_ko_3 = '우리 매니저가 모든 변경 사항을 승인해야 해요.', example_en_4 = 'They approved the deal after one round of talks.', example_ko_4 = '그들은 한 차례의 협상 후에 거래를 승인했어요.', example_en_5 = 'Approval from both sides is required before signing.', example_ko_5 = '서명 전에 양측의 승인이 필요해요.' WHERE id = 'w_negotiation_B1_24';
UPDATE words SET example_en_2 = 'We managed to negotiate down the setup fee.', example_ko_2 = '설치 수수료를 낮추는 데 성공했어요.', example_en_3 = 'She negotiated down from the original price by 15%.', example_ko_3 = '그녀는 원래 가격에서 15% 낮추는 데 성공했어요.', example_en_4 = 'He negotiated down the penalty to almost nothing.', example_ko_4 = '그는 위약금을 거의 없는 수준으로 낮췄어요.', example_en_5 = 'With patience, you can always negotiate down.', example_ko_5 = '인내심이 있으면 항상 가격을 낮출 수 있어요.' WHERE id = 'w_negotiation_B1_25';
UPDATE words SET example_en_2 = 'Each party has clear obligations in this deal.', example_ko_2 = '이 거래에서 각 당사자는 명확한 의무가 있어요.', example_en_3 = 'Meeting your obligations builds lasting trust.', example_ko_3 = '의무를 이행하는 것이 지속적인 신뢰를 구축해요.', example_en_4 = 'She fulfilled all her obligations on time.', example_ko_4 = '그녀는 모든 의무를 제때 이행했어요.', example_en_5 = 'List obligations clearly to avoid disputes later.', example_ko_5 = '나중의 분쟁을 피하기 위해 의무를 명확하게 나열하세요.' WHERE id = 'w_negotiation_B1_26';
UPDATE words SET example_en_2 = 'The market rate is our main benchmark here.', example_ko_2 = '시장 가격이 여기서 우리의 주요 기준이에요.', example_en_3 = 'Use a benchmark to evaluate any offer you receive.', example_ko_3 = '받은 제안을 평가하기 위해 기준을 사용하세요.', example_en_4 = 'She set a clear benchmark before negotiations began.', example_ko_4 = '그녀는 협상이 시작되기 전에 명확한 기준을 설정했어요.', example_en_5 = 'Compare the offer to the industry benchmark.', example_ko_5 = '제안을 업계 기준과 비교하세요.' WHERE id = 'w_negotiation_B1_27';
UPDATE words SET example_en_2 = 'High volume orders reduce the unit price.', example_ko_2 = '대량 주문이 단가를 낮춰요.', example_en_3 = 'The volume discount kicks in at 500 units.', example_ko_3 = '물량 할인은 500개부터 적용돼요.', example_en_4 = 'They increased volume to gain more leverage.', example_ko_4 = '그들은 더 강한 협상력을 얻기 위해 물량을 늘렸어요.', example_en_5 = 'Agree on volume commitments before locking in price.', example_ko_5 = '가격을 확정하기 전에 물량 약속에 합의하세요.' WHERE id = 'w_negotiation_B1_28';
UPDATE words SET example_en_2 = 'All agreements must be confirmed in writing.', example_ko_2 = '모든 합의는 서면으로 확인되어야 해요.', example_en_3 = 'She asked for the offer in writing immediately.', example_ko_3 = '그녀는 즉시 서면으로 제안을 요청했어요.', example_en_4 = 'Get everything in writing before you proceed.', example_ko_4 = '진행하기 전에 모든 것을 서면으로 받으세요.', example_en_5 = 'Verbal agreements are only valid in writing here.', example_ko_5 = '구두 합의는 여기서는 서면으로만 유효해요.' WHERE id = 'w_negotiation_B1_29';
UPDATE words SET example_en_2 = 'We want an exclusive supply deal for three years.', example_ko_2 = '3년간 독점 공급 계약을 원해요.', example_en_3 = 'Exclusive rights come with higher volume commitments.', example_ko_3 = '독점권에는 더 높은 물량 약속이 따라요.', example_en_4 = 'They offered exclusive territory rights in Korea.', example_ko_4 = '그들은 한국에서의 독점 영역권을 제안했어요.', example_en_5 = 'Negotiate exclusivity carefully — it limits your options.', example_ko_5 = '독점권을 신중하게 협상하세요 — 선택지를 제한해요.' WHERE id = 'w_negotiation_B1_30';
UPDATE words SET example_en_2 = 'The minimum order is two hundred units per batch.', example_ko_2 = '최소 주문은 배치당 200개예요.', example_en_3 = 'She negotiated the minimum down to fifty units.', example_ko_3 = '그녀는 최소 주문량을 50개로 낮추는 협상을 했어요.', example_en_4 = 'A lower minimum makes it easier to start.', example_ko_4 = '낮은 최소 주문이 시작을 더 쉽게 만들어요.', example_en_5 = 'The minimum requirement is stated in the contract.', example_ko_5 = '최소 요건이 계약서에 명시되어 있어요.' WHERE id = 'w_negotiation_B1_31';
UPDATE words SET example_en_2 = 'They requested a three-month extension.', example_ko_2 = '그들은 3개월 연장을 요청했어요.', example_en_3 = 'An extension was granted due to supply issues.', example_ko_3 = '공급 문제로 연장이 허가됐어요.', example_en_4 = 'Negotiate the extension before the deadline passes.', example_ko_4 = '마감일이 지나기 전에 연장을 협상하세요.', example_en_5 = 'The contract extension was signed last week.', example_ko_5 = '계약 연장이 지난주에 서명됐어요.' WHERE id = 'w_negotiation_B1_32';
UPDATE words SET example_en_2 = 'There is little headroom on the final offer.', example_ko_2 = '최종 제안에 협상 여지가 거의 없어요.', example_en_3 = 'Find the headroom before entering the room.', example_ko_3 = '회의실에 들어가기 전에 협상 여지를 파악하세요.', example_en_4 = 'They showed headroom by revising the price twice.', example_ko_4 = '그들은 가격을 두 번 수정함으로써 협상 여지를 보여줬어요.', example_en_5 = 'No headroom means the offer is truly final.', example_ko_5 = '협상 여지가 없다면 제안이 진짜 최종이에요.' WHERE id = 'w_negotiation_B1_33';
UPDATE words SET example_en_2 = 'We will walk away if they refuse to move.', example_ko_2 = '그들이 움직이기를 거부하면 물러날 거예요.', example_en_3 = 'Knowing when to walk away gives you power.', example_ko_3 = '언제 물러나야 할지 아는 것이 힘을 줘요.', example_en_4 = 'She walked away and got a better offer next day.', example_ko_4 = '그녀는 물러났고 다음 날 더 나은 제안을 받았어요.', example_en_5 = 'Do not be afraid to walk away from a bad deal.', example_ko_5 = '나쁜 거래에서 물러나는 것을 두려워하지 마세요.' WHERE id = 'w_negotiation_B1_34';
UPDATE words SET example_en_2 = 'The penalty clause covers both delivery and quality.', example_ko_2 = '위약금 조항은 납품과 품질 모두를 다루어요.', example_en_3 = 'She reviewed the penalty clause with a lawyer.', example_ko_3 = '그녀는 변호사와 함께 위약금 조항을 검토했어요.', example_en_4 = 'A well-drafted penalty clause deters non-performance.', example_ko_4 = '잘 작성된 위약금 조항이 불이행을 억제해요.', example_en_5 = 'Agree on the penalty clause before signing.', example_ko_5 = '서명하기 전에 위약금 조항에 합의하세요.' WHERE id = 'w_negotiation_B1_35';

