UPDATE words SET example_en_2 = 'A fiduciary must prioritize the client''s interests.', example_ko_2 = '수탁자는 고객의 이익을 우선시해야 해요.', example_en_3 = 'The fund manager owes fiduciary duties to investors.', example_ko_3 = '펀드 매니저는 투자자에게 신탁 의무를 집니다.', example_en_4 = 'Fiduciary responsibility cannot be delegated away.', example_ko_4 = '신탁 책임은 위임할 수 없어요.', example_en_5 = 'She breached her fiduciary duty by self-dealing.', example_ko_5 = '그녀는 자기 거래로 신탁 의무를 위반했어요.' WHERE id = 'w_negotiation_C1_01';
UPDATE words SET example_en_2 = 'Subrogation rights belong to the insurer after payout.', example_ko_2 = '지급 후 대위변제 권리는 보험사에 귀속돼요.', example_en_3 = 'She negotiated a waiver of subrogation rights.', example_ko_3 = '그녀는 대위변제 권리의 포기를 협상했어요.', example_en_4 = 'Subrogation allows recovery of amounts paid out.', example_ko_4 = '대위변제는 지급된 금액의 회수를 허용해요.', example_en_5 = 'The subrogation clause was a key point of dispute.', example_ko_5 = '대위변제 조항이 분쟁의 핵심 포인트였어요.' WHERE id = 'w_negotiation_C1_02';
UPDATE words SET example_en_2 = 'The indemnification covers all defense costs.', example_ko_2 = '손해 배상은 모든 방어 비용을 포함해요.', example_en_3 = 'Broad indemnification language was heavily negotiated.', example_ko_3 = '광범위한 손해 배상 표현은 치열하게 협상됐어요.', example_en_4 = 'She limited indemnification to direct damages only.', example_ko_4 = '그녀는 손해 배상을 직접 손해로만 제한했어요.', example_en_5 = 'Mutual indemnification is fairer than one-sided terms.', example_ko_5 = '상호 손해 배상이 일방적인 조건보다 더 공정해요.' WHERE id = 'w_negotiation_C1_03';
UPDATE words SET example_en_2 = 'The non-compete covenant runs for 24 months.', example_ko_2 = '경쟁 금지 약정은 24개월간 지속돼요.', example_en_3 = 'She challenged the covenant as overly broad.', example_ko_3 = '그녀는 약정이 지나치게 광범위하다고 이의를 제기했어요.', example_en_4 = 'A covenant of quiet enjoyment protects the tenant.', example_ko_4 = '평온한 사용 약정이 세입자를 보호해요.', example_en_5 = 'The covenant was enforceable within the agreed region.', example_ko_5 = '약정은 합의된 지역 내에서 집행 가능했어요.' WHERE id = 'w_negotiation_C1_04';
UPDATE words SET example_en_2 = 'The bank holds a lien on all company assets.', example_ko_2 = '은행이 모든 회사 자산에 유치권을 보유하고 있어요.', example_en_3 = 'The lien must be released before the sale closes.', example_ko_3 = '매매가 종결되기 전에 유치권이 해제되어야 해요.', example_en_4 = 'She discovered a hidden lien during due diligence.', example_ko_4 = '그녀는 실사 중에 숨겨진 유치권을 발견했어요.', example_en_5 = 'A lien gives the holder priority over other creditors.', example_ko_5 = '유치권은 보유자에게 다른 채권자에 대한 우선권을 줘요.' WHERE id = 'w_negotiation_C1_05';
UPDATE words SET example_en_2 = 'She applied for an injunction to freeze the assets.', example_ko_2 = '그녀는 자산을 동결하기 위해 금지 명령을 신청했어요.', example_en_3 = 'The injunction prevented the deal from closing.', example_ko_3 = '금지 명령이 거래 종결을 막았어요.', example_en_4 = 'An interim injunction was granted within 24 hours.', example_ko_4 = '24시간 이내에 임시 금지 명령이 허가됐어요.', example_en_5 = 'The threat of an injunction brought them back to talks.', example_ko_5 = '금지 명령 위협이 그들을 협상 테이블로 돌아오게 했어요.' WHERE id = 'w_negotiation_C1_06';
UPDATE words SET example_en_2 = 'The supplier''s delay was a clear breach of contract.', example_ko_2 = '공급업체의 지연은 명백한 계약 위반이었어요.', example_en_3 = 'She documented every breach meticulously.', example_ko_3 = '그녀는 모든 위반을 꼼꼼하게 문서화했어요.', example_en_4 = 'A repudiatory breach entitles the other party to exit.', example_ko_4 = '부인적 위반은 상대방에게 계약 해제권을 줘요.', example_en_5 = 'Give written notice of breach before claiming damages.', example_ko_5 = '손해배상을 청구하기 전에 위반의 서면 통보를 하세요.' WHERE id = 'w_negotiation_C1_07';
UPDATE words SET example_en_2 = 'The remedy for late delivery is a price reduction.', example_ko_2 = '납품 지연에 대한 구제책은 가격 인하예요.', example_en_3 = 'She sought an equitable remedy through the courts.', example_ko_3 = '그녀는 법원을 통해 형평법적 구제책을 구했어요.', example_en_4 = 'No remedy was available because the claim was time-barred.', example_ko_4 = '청구권이 시효 소멸되어 구제책이 없었어요.', example_en_5 = 'Agree on the remedy for breach before signing.', example_ko_5 = '서명 전에 위반에 대한 구제책에 합의하세요.' WHERE id = 'w_negotiation_C1_08';
UPDATE words SET example_en_2 = 'Disputes go to Singapore jurisdiction by default.', example_ko_2 = '분쟁은 기본적으로 싱가포르 관할권으로 가요.', example_en_3 = 'She challenged the exclusive jurisdiction clause.', example_ko_3 = '그녀는 전속 관할권 조항에 이의를 제기했어요.', example_en_4 = 'Jurisdiction clauses prevent forum shopping.', example_ko_4 = '관할권 조항이 법정지 쇼핑을 방지해요.', example_en_5 = 'Both parties agreed to submit to English jurisdiction.', example_ko_5 = '양 당사자는 영국 관할권에 복종하기로 동의했어요.' WHERE id = 'w_negotiation_C1_09';
UPDATE words SET example_en_2 = 'The tortious act caused significant financial harm.', example_ko_2 = '불법 행위가 심각한 재정적 피해를 야기했어요.', example_en_3 = 'She sued for tortious interference with her contract.', example_ko_3 = '그녀는 계약에 대한 불법 행위 간섭으로 소송했어요.', example_en_4 = 'Tortious liability can arise outside of contract.', example_ko_4 = '불법 행위 책임은 계약 밖에서 발생할 수 있어요.', example_en_5 = 'Prove tortious conduct to seek compensation.', example_ko_5 = '보상을 구하려면 불법 행위를 증명하세요.' WHERE id = 'w_negotiation_C1_10';
UPDATE words SET example_en_2 = 'Third parties lack privity and cannot sue under this deal.', example_ko_2 = '제3자는 계약 당사자 관계가 없어 이 거래에서 소송할 수 없어요.', example_en_3 = 'The doctrine of privity limits who can enforce a contract.', example_ko_3 = '계약 당사자 관계 원칙이 계약을 집행할 수 있는 사람을 제한해요.', example_en_4 = 'She relied on privity to dismiss the third-party claim.', example_ko_4 = '그녀는 제3자 청구를 기각하기 위해 계약 당사자 관계에 의존했어요.', example_en_5 = 'Privity of contract is a fundamental common law rule.', example_ko_5 = '계약 당사자 관계는 기본적인 보통법 규칙이에요.' WHERE id = 'w_negotiation_C1_11';
UPDATE words SET example_en_2 = 'Estoppel prevented them from changing their position.', example_ko_2 = '금반언이 그들이 입장을 바꾸는 것을 막았어요.', example_en_3 = 'She raised estoppel as a defence in the hearing.', example_ko_3 = '그녀는 심리에서 금반언을 방어로 제기했어요.', example_en_4 = 'Estoppel can arise from conduct as well as words.', example_ko_4 = '금반언은 말뿐만 아니라 행위에서도 발생할 수 있어요.', example_en_5 = 'The court applied estoppel to uphold the agreement.', example_ko_5 = '법원은 합의를 지지하기 위해 금반언을 적용했어요.' WHERE id = 'w_negotiation_C1_12';
UPDATE words SET example_en_2 = 'Rescission restored both parties to their original position.', example_ko_2 = '계약 해제가 양 당사자를 원래 위치로 회복시켰어요.', example_en_3 = 'She sought rescission on the grounds of misrepresentation.', example_ko_3 = '그녀는 허위 진술을 근거로 계약 해제를 구했어요.', example_en_4 = 'Rescission is not available once the contract is executed.', example_ko_4 = '계약이 이행된 후에는 계약 해제를 구할 수 없어요.', example_en_5 = 'The court granted rescission due to fraudulent terms.', example_ko_5 = '법원은 사기적 조건으로 계약 해제를 허가했어요.' WHERE id = 'w_negotiation_C1_13';
UPDATE words SET example_en_2 = 'Novation discharged the original vendor entirely.', example_ko_2 = '계약 갱신이 원래 공급업체를 완전히 면제했어요.', example_en_3 = 'She proposed novation to bring in a new partner.', example_ko_3 = '그녀는 새 파트너를 참여시키기 위해 계약 갱신을 제안했어요.', example_en_4 = 'Novation requires consent from all three parties.', example_ko_4 = '계약 갱신은 세 당사자 모두의 동의가 필요해요.', example_en_5 = 'The novation agreement was signed at the closing meeting.', example_ko_5 = '계약 갱신 합의서가 종결 회의에서 서명됐어요.' WHERE id = 'w_negotiation_C1_14';
UPDATE words SET example_en_2 = 'The promissory note carries a 6% annual interest rate.', example_ko_2 = '약속 어음에는 연 6% 이자율이 적용돼요.', example_en_3 = 'She endorsed the promissory note to a third party.', example_ko_3 = '그녀는 약속 어음을 제3자에게 배서했어요.', example_en_4 = 'A promissory note is a formal written promise to pay.', example_ko_4 = '약속 어음은 지불의 공식 서면 약속이에요.', example_en_5 = 'He defaulted on the promissory note last quarter.', example_ko_5 = '그는 지난 분기에 약속 어음을 이행하지 못했어요.' WHERE id = 'w_negotiation_C1_15';
UPDATE words SET example_en_2 = 'Both parties still have executory obligations under this deal.', example_ko_2 = '양 당사자 모두 이 거래에서 아직 미이행 의무가 있어요.', example_en_3 = 'The executory portion of the contract was assigned.', example_ko_3 = '계약의 미이행 부분이 양도됐어요.', example_en_4 = 'Executory contracts may be rejected in insolvency.', example_ko_4 = '미이행 계약은 파산 절차에서 거부될 수 있어요.', example_en_5 = 'The executory obligations transfer with a novation.', example_ko_5 = '미이행 의무는 계약 갱신과 함께 이전돼요.' WHERE id = 'w_negotiation_C1_16';
UPDATE words SET example_en_2 = 'They agreed on liquidated damages of $500 per day late.', example_ko_2 = '그들은 하루 늦을 때마다 500달러의 확정 손해배상에 합의했어요.', example_en_3 = 'Liquidated damages must not be a penalty under English law.', example_ko_3 = '확정 손해배상은 영국법상 위약금이 되어서는 안 돼요.', example_en_4 = 'She argued the liquidated damages rate was disproportionate.', example_ko_4 = '그녀는 확정 손해배상 비율이 불균형적이라고 주장했어요.', example_en_5 = 'Liquidated damages provide certainty for both parties.', example_ko_5 = '확정 손해배상은 양 당사자에게 확실성을 제공해요.' WHERE id = 'w_negotiation_C1_17';
UPDATE words SET example_en_2 = 'The buyer sought specific performance of the land contract.', example_ko_2 = '매수인은 토지 계약의 특정 이행을 구했어요.', example_en_3 = 'Specific performance is granted when damages are inadequate.', example_ko_3 = '손해배상이 불충분할 때 특정 이행이 허가돼요.', example_en_4 = 'She preferred specific performance over a damages award.', example_ko_4 = '그녀는 손해배상 판결보다 특정 이행을 선호했어요.', example_en_5 = 'Courts rarely grant specific performance for services.', example_ko_5 = '법원은 서비스에 대한 특정 이행을 거의 허가하지 않아요.' WHERE id = 'w_negotiation_C1_18';
UPDATE words SET example_en_2 = 'The unexpected war triggered frustration of contract.', example_ko_2 = '예상치 못한 전쟁이 계약 이행 불능을 발동시켰어요.', example_en_3 = 'Frustration discharged both parties from obligations.', example_ko_3 = '계약 이행 불능으로 양 당사자가 의무에서 면제됐어요.', example_en_4 = 'She argued frustration due to a change in law.', example_ko_4 = '그녀는 법률 변경으로 인한 계약 이행 불능을 주장했어요.', example_en_5 = 'Frustration is narrowly interpreted by the courts.', example_ko_5 = '계약 이행 불능은 법원에 의해 좁게 해석돼요.' WHERE id = 'w_negotiation_C1_19';
UPDATE words SET example_en_2 = 'The implied term requires reasonable care in performance.', example_ko_2 = '묵시적 조항은 이행에 합리적인 주의를 요구해요.', example_en_3 = 'Courts may imply a term to give business efficacy.', example_ko_3 = '법원은 사업 효력을 부여하기 위해 조항을 묵시적으로 포함시킬 수 있어요.', example_en_4 = 'She argued an implied term of good faith applied.', example_ko_4 = '그녀는 선의의 묵시적 조항이 적용된다고 주장했어요.', example_en_5 = 'An implied term cannot contradict an express term.', example_ko_5 = '묵시적 조항은 명시적 조항에 모순될 수 없어요.' WHERE id = 'w_negotiation_C1_20';
UPDATE words SET example_en_2 = 'The exculpatory clause tried to exclude all liability.', example_ko_2 = '면책 조항이 모든 책임을 배제하려 했어요.', example_en_3 = 'An exculpatory clause for negligence was struck down.', example_ko_3 = '과실에 대한 면책 조항이 무효화됐어요.', example_en_4 = 'She negotiated limits on the exculpatory clause.', example_ko_4 = '그녀는 면책 조항에 제한을 협상했어요.', example_en_5 = 'Exculpatory clauses are interpreted strictly by courts.', example_ko_5 = '면책 조항은 법원에 의해 엄격하게 해석돼요.' WHERE id = 'w_negotiation_C1_21';
UPDATE words SET example_en_2 = 'The assignment of rights was prohibited by the contract.', example_ko_2 = '권리 양도가 계약에 의해 금지됐어요.', example_en_3 = 'She assigned her rights under the contract to a trustee.', example_ko_3 = '그녀는 계약상 권리를 수탁자에게 양도했어요.', example_en_4 = 'An assignment transfers benefits but not burdens.', example_ko_4 = '양도는 이익은 이전하지만 부담은 이전하지 않아요.', example_en_5 = 'Always get consent before any assignment of contract.', example_ko_5 = '계약 양도 전에 항상 동의를 받으세요.' WHERE id = 'w_negotiation_C1_22';
UPDATE words SET example_en_2 = 'The acceleration clause was triggered by non-payment.', example_ko_2 = '기한 이익 상실 조항이 미지불로 인해 발동됐어요.', example_en_3 = 'She negotiated to remove the acceleration clause.', example_ko_3 = '그녀는 기한 이익 상실 조항 제거를 협상했어요.', example_en_4 = 'The lender exercised the acceleration clause immediately.', example_ko_4 = '대출자가 즉시 기한 이익 상실 조항을 행사했어요.', example_en_5 = 'An acceleration clause makes the entire debt due now.', example_ko_5 = '기한 이익 상실 조항은 전체 채무를 즉시 이행하게 만들어요.' WHERE id = 'w_negotiation_C1_23';
UPDATE words SET example_en_2 = 'The indemnity cap was set at two times the contract value.', example_ko_2 = '배상 한도액이 계약 금액의 두 배로 설정됐어요.', example_en_3 = 'She pushed for a lower indemnity cap in the final draft.', example_ko_3 = '그녀는 최종 초안에서 더 낮은 배상 한도액을 요구했어요.', example_en_4 = 'An uncapped indemnity is a major risk to avoid.', example_ko_4 = '무제한 배상은 피해야 할 중요한 위험이에요.', example_en_5 = 'Negotiate the indemnity cap early in the process.', example_ko_5 = '과정 초반에 배상 한도액을 협상하세요.' WHERE id = 'w_negotiation_C1_24';
UPDATE words SET example_en_2 = 'The contract excludes all consequential loss claims.', example_ko_2 = '계약은 모든 간접 손해 청구를 배제해요.', example_en_3 = 'She sought consequential loss damages and was refused.', example_ko_3 = '그녀는 간접 손해 배상을 구했지만 거부됐어요.', example_en_4 = 'Consequential loss can vastly exceed direct loss.', example_ko_4 = '간접 손해는 직접 손해를 크게 초과할 수 있어요.', example_en_5 = 'Mutual exclusion of consequential loss is standard.', example_ko_5 = '상호 간접 손해 배제가 표준적이에요.' WHERE id = 'w_negotiation_C1_25';
UPDATE words SET example_en_2 = 'She exercised her right of set-off against the invoice.', example_ko_2 = '그녀는 청구서에 대해 상계권을 행사했어요.', example_en_3 = 'The contract expressly excluded the right of set-off.', example_ko_3 = '계약이 상계권을 명시적으로 배제했어요.', example_en_4 = 'He used set-off to reduce the amount due.', example_ko_4 = '그는 납부 금액을 줄이기 위해 상계를 사용했어요.', example_en_5 = 'A set-off clause must be very clearly drafted.', example_ko_5 = '상계 조항은 매우 명확하게 작성되어야 해요.' WHERE id = 'w_negotiation_C1_26';
UPDATE words SET example_en_2 = 'The retention of title clause protects unpaid sellers.', example_ko_2 = '소유권 유보 조항이 미지급된 판매자를 보호해요.', example_en_3 = 'She relied on retention of title in the insolvency case.', example_ko_3 = '그녀는 파산 사건에서 소유권 유보에 의존했어요.', example_en_4 = 'Insert retention of title in all supply agreements.', example_ko_4 = '모든 공급 계약에 소유권 유보를 삽입하세요.', example_en_5 = 'Retention of title is worthless if goods are mixed.', example_ko_5 = '소유권 유보는 상품이 혼합되면 무가치해요.' WHERE id = 'w_negotiation_C1_27';
UPDATE words SET example_en_2 = 'The entire agreement clause prevents side letters.', example_ko_2 = '전체 합의 조항이 부수 서신을 방지해요.', example_en_3 = 'She relied on the entire agreement clause in the dispute.', example_ko_3 = '그녀는 분쟁에서 전체 합의 조항에 의존했어요.', example_en_4 = 'An entire agreement clause negates prior representations.', example_ko_4 = '전체 합의 조항이 이전 진술을 무효화해요.', example_en_5 = 'The entire agreement clause must be explicit and clear.', example_ko_5 = '전체 합의 조항은 명시적이고 명확해야 해요.' WHERE id = 'w_negotiation_C1_28';
UPDATE words SET example_en_2 = 'The non-compete clause restricts work in this sector.', example_ko_2 = '경쟁 금지 조항이 이 분야에서의 업무를 제한해요.', example_en_3 = 'She challenged the non-compete as disproportionate.', example_ko_3 = '그녀는 경쟁 금지가 불균형적이라고 이의를 제기했어요.', example_en_4 = 'A non-compete must be limited in scope and time.', example_ko_4 = '경쟁 금지는 범위와 기간이 제한되어야 해요.', example_en_5 = 'The non-compete applies globally for one year.', example_ko_5 = '경쟁 금지는 1년간 전 세계적으로 적용돼요.' WHERE id = 'w_negotiation_C1_29';
UPDATE words SET example_en_2 = 'The lender exercised its step-in rights after default.', example_ko_2 = '대출자가 채무불이행 후 직접 이행권을 행사했어요.', example_en_3 = 'Step-in rights protect funders in infrastructure deals.', example_ko_3 = '직접 이행권이 인프라 거래에서 자금 제공자를 보호해요.', example_en_4 = 'She negotiated step-in rights as a condition of lending.', example_ko_4 = '그녀는 대출 조건으로 직접 이행권을 협상했어요.', example_en_5 = 'Step-in rights must be notified in advance to all parties.', example_ko_5 = '직접 이행권은 모든 당사자에게 사전에 통보되어야 해요.' WHERE id = 'w_negotiation_C1_30';
UPDATE words SET example_en_2 = 'All conditions precedent must be met before drawdown.', example_ko_2 = '대출 실행 전에 모든 선행 조건이 충족되어야 해요.', example_en_3 = 'She waived one condition precedent to speed things up.', example_ko_3 = '그녀는 속도를 높이기 위해 선행 조건 하나를 포기했어요.', example_en_4 = 'The conditions precedent list ran to fifteen items.', example_ko_4 = '선행 조건 목록이 15개 항목에 달했어요.', example_en_5 = 'Failure to satisfy conditions precedent voids the deal.', example_ko_5 = '선행 조건 충족 실패는 거래를 무효화해요.' WHERE id = 'w_negotiation_C1_31';
UPDATE words SET example_en_2 = 'Every variation order must be costed before it is signed.', example_ko_2 = '모든 변경 명령서는 서명 전에 비용이 산정되어야 해요.', example_en_3 = 'She issued a variation order to extend the timeline.', example_ko_3 = '그녀는 타임라인을 연장하기 위해 변경 명령서를 발행했어요.', example_en_4 = 'Variation orders must be approved in writing by both sides.', example_ko_4 = '변경 명령서는 양측에서 서면으로 승인되어야 해요.', example_en_5 = 'Manage variation orders carefully to control budget.', example_ko_5 = '예산을 통제하기 위해 변경 명령서를 신중하게 관리하세요.' WHERE id = 'w_negotiation_C1_32';
UPDATE words SET example_en_2 = 'The court applied contra proferentem to limit liability.', example_ko_2 = '법원은 책임을 제한하기 위해 제안자 불리 원칙을 적용했어요.', example_en_3 = 'She used contra proferentem to argue the broader interpretation.', example_ko_3 = '그녀는 더 넓은 해석을 주장하기 위해 제안자 불리 원칙을 사용했어요.', example_en_4 = 'Contra proferentem only applies when terms are genuinely ambiguous.', example_ko_4 = '제안자 불리 원칙은 조건이 진정으로 모호할 때만 적용돼요.', example_en_5 = 'Clear drafting removes the risk of contra proferentem.', example_ko_5 = '명확한 작성이 제안자 불리 원칙의 위험을 제거해요.' WHERE id = 'w_negotiation_C1_33';
UPDATE words SET example_en_2 = 'The pandemic was accepted as a force majeure event.', example_ko_2 = '팬데믹이 불가항력 사태로 인정됐어요.', example_en_3 = 'She drafted a wide force majeure clause to be safe.', example_ko_3 = '그녀는 안전을 위해 광범위한 불가항력 조항을 작성했어요.', example_en_4 = 'The force majeure clause must list events specifically.', example_ko_4 = '불가항력 조항은 사태를 구체적으로 나열해야 해요.', example_en_5 = 'Notice under the force majeure clause must be prompt.', example_ko_5 = '불가항력 조항에 따른 통보는 즉각적이어야 해요.' WHERE id = 'w_negotiation_C1_34';
UPDATE words SET example_en_2 = 'She owed a duty of care to all clients she advised.', example_ko_2 = '그녀는 조언한 모든 고객에게 주의 의무를 졌어요.', example_en_3 = 'A duty of care arises from the relationship of reliance.', example_ko_3 = '주의 의무는 신뢰 관계에서 발생해요.', example_en_4 = 'Breaching a duty of care can lead to negligence claims.', example_ko_4 = '주의 의무 위반은 과실 청구로 이어질 수 있어요.', example_en_5 = 'The duty of care standard is measured objectively.', example_ko_5 = '주의 의무 기준은 객관적으로 측정돼요.' WHERE id = 'w_negotiation_C1_35';

